mapper.select:
select m.id, m.major_name, m.major_code, m.remark, d.department_name, m.department_id, m.status, m.create_time from major m left join department d on m.department_id = d.id
and (m.major_name like concat('%', #{keyword}, '%') or m.major_code like concat('%', #{keyword}, '%'))
and m.department_id = #{departmentId}
and m.status = #{status}
order by m.create_time desc

mapper.update:
update major
major_name = #{majorName}, major_code = #{majorCode}, remark = #{remark}, department_id = #{departmentId}, update_time = NOW()
where id = #{id}
